// --- helpers ----------------------------------------------------
const DAYS = ["日","月","火","水","木","金","土"];
function todayKey() {
  const d = new Date();
  // 午前3時未満は前日扱い
  if (d.getHours() < 3) d.setDate(d.getDate() - 1);
  return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;
}
function pad(n){ return String(n).padStart(2,"0"); }
function fmtDate(k){
  const [y,m,d] = k.split("-");
  return `${+m}月${+d}日（${DAYS[new Date(+y,+m-1,+d).getDay()]}）`;
}

