const SUPA_URL = "https://uxwevkooivnepuzqzfdz.supabase.co";
const SUPA_KEY = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InV4d2V2a29vaXZuZXB1enF6ZmR6Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzIwNTE5MzMsImV4cCI6MjA4NzYyNzkzM30.FEOWSyZ4139D3BC_mQT8qyIocf2Yw8Xwa4NmbfIORNE";

async function sbFetch(path, opts={}) {
  const res = await fetch(`${SUPA_URL}/rest/v1/${path}`, {
    ...opts,
    headers: {
      "apikey": SUPA_KEY,
      "Authorization": `Bearer ${SUPA_KEY}`,
      "Content-Type": "application/json",
      "Prefer": "return=representation",
      ...(opts.headers||{})
    }
  });
  if (!res.ok) { const e = await res.text(); throw new Error(e); }
  const text = await res.text();
  return text ? JSON.parse(text) : [];
}

// --- athlete roster (Supabase + localStorage fallback) ----------
function getRoster() {
  try { return JSON.parse(localStorage.getItem("bb_roster") || "[]"); }
  catch { return []; }
}
function saveRoster(roster) {
  localStorage.setItem("bb_roster", JSON.stringify(roster));
}
async function syncRosterToSupabase(athlete) {
  try {
    await sbFetch("roster", {
      method: "POST",
      body: JSON.stringify(athlete),
      headers: { "Prefer": "resolution=merge-duplicates,return=representation" }
    });
  } catch(e) { console.warn("Supabase roster sync failed", e); }
}
async function fetchRosterFromSupabase() {
  try {
    return await sbFetch("roster?select=*&order=created_at.asc");
  } catch(e) { console.warn("Supabase roster fetch failed", e); return []; }
}
function getRecords(athleteId) {
  try { return JSON.parse(localStorage.getItem(`bb_rec_${athleteId}`) || "{}"); }
  catch { return {}; }
}
function saveRecords(athleteId, data) {
  localStorage.setItem(`bb_rec_${athleteId}`, JSON.stringify(data));
}
async function syncRecordToSupabase(athlete, dateKey, record) {
  try {
    const kcal_total = (() => {
      let t = 0;
      if (record.meals) Object.values(record.meals).forEach(m => { t += parseFloat(m.kcal) || 0; });
      if (record.snacks) record.snacks.forEach(s => { t += parseFloat(s.kcal) || 0; });
      return t;
    })();
    await sbFetch("records", {
      method: "POST",
      body: JSON.stringify({
        athlete_id: athlete.id,
        athlete_name: athlete.name,
        record_date: dateKey,
        data: record,
        weight: parseFloat(record.weight) || null,
        sleep: parseFloat(record.sleep) || null,
        fatigue: record.fatigue ?? null,
        stamina: record.stamina ?? null,
        kcal_total: kcal_total || null,
        meals: record.meals || null,
        snacks: record.snacks || null,
        pain: record.pain || null,
        throwing_status: record.throwingStatus || null,
        memo: record.memo || null,
        saved: record.saved || false,
      }),
      headers: { "Prefer": "resolution=merge-duplicates,return=representation" }
    });
  } catch(e) { console.warn("Supabase record sync failed", e); throw e; }
}
async function fetchAllRecordsFromSupabase() {
  try {
    return await sbFetch("records?select=*&order=record_date.desc");
  } catch(e) { console.warn("Supabase records fetch failed", e); return []; }
}

// Supabaseの行からrecordオブジェクトを復元（個別カラム優先、dataをフォールバック）
function rowToRecord(row) {
  const base = row.data || {};
  const baseMeals = row.meals || base.meals || {};
  const meals = {
    morning: baseMeals.morning || { kcal:"", note:"", items:[] },
    lunch:   baseMeals.lunch   || { kcal:"", note:"", items:[] },
    dinner:  baseMeals.dinner  || { kcal:"", note:"", items:[] },
  };
  return {
    ...base,
    weight: row.weight != null ? String(row.weight) : (base.weight || ""),
    sleep: row.sleep != null ? String(row.sleep) : (base.sleep || ""),
    fatigue: row.fatigue != null ? row.fatigue : (base.fatigue ?? 2),
    stamina: row.stamina != null ? row.stamina : (base.stamina ?? 50),
    meals,
    snacks: row.snacks || base.snacks || [],
    pain: row.pain || base.pain || [],
    throwingStatus: row.throwing_status || base.throwingStatus || "",
    memo: row.memo || base.memo || "",
    saved: row.saved ?? base.saved ?? false,
  };
}
function calcKcal(rec) {
  if (!rec) return 0;
  let t = 0;
  if (rec.meals) Object.values(rec.meals).forEach(m => { t += parseFloat(m.kcal) || 0; });
  if (rec.snacks) rec.snacks.forEach(s => { t += parseFloat(s.kcal) || 0; });
  return t || (rec.calories ? parseInt(rec.calories) : 0);
}

